// ─── Block system ────────────────────────────────────────────────────────────

export type BlockType = "text" | "line-items" | "deliverables" | "pricing" | "next-steps" | "notes";

export interface BaseBlock {
  blockId: string;
  type: BlockType;
  order: number;
}

export interface TextBlock extends BaseBlock {
  type: "text";
  data: { heading: string; body: string };
}

export interface LineItemsBlock extends BaseBlock {
  type: "line-items";
  data: { heading: string; items: LineItem[]; discount: number };
}

export interface DeliverablesBlock extends BaseBlock {
  type: "deliverables";
  data: { items: Deliverable[] };
}

export interface PricingBlock extends BaseBlock {
  type: "pricing";
  data: {
    fixedPrice: number;
    listPrice?: number;
    preferentialNote?: string;
    timeline?: string;
    paymentTerms?: string;
  };
}

export interface NextStepsBlock extends BaseBlock {
  type: "next-steps";
  data: { steps: string[] };
}

export interface NotesBlock extends BaseBlock {
  type: "notes";
  data: { body: string };
}

export type QuoteBlock =
  | TextBlock
  | LineItemsBlock
  | DeliverablesBlock
  | PricingBlock
  | NextStepsBlock
  | NotesBlock;

// ─── Block registry ──────────────────────────────────────────────────────────

export const BLOCK_REGISTRY: Record<
  BlockType,
  {
    icon: string;
    labelKey: string;
    allowMultiple: boolean;
    createDefault: () => QuoteBlock["data"];
  }
> = {
  text: {
    icon: "Type",
    labelKey: "textSection",
    allowMultiple: true,
    createDefault: () => ({ heading: "", body: "" }),
  },
  "line-items": {
    icon: "Table",
    labelKey: "lineItemsBlock",
    allowMultiple: true,
    createDefault: () => ({
      heading: "",
      items: [{ id: crypto.randomUUID().slice(0, 6), description: "", quantity: 1, unitPrice: 0 }],
      discount: 0,
    }),
  },
  deliverables: {
    icon: "ListChecks",
    labelKey: "deliverablesBlock",
    allowMultiple: true,
    createDefault: () => ({ items: [] }),
  },
  pricing: {
    icon: "DollarSign",
    labelKey: "pricingBlock",
    allowMultiple: false,
    createDefault: () => ({ fixedPrice: 0 }),
  },
  "next-steps": {
    icon: "ListOrdered",
    labelKey: "nextStepsBlock",
    allowMultiple: false,
    createDefault: () => ({ steps: [""] }),
  },
  notes: {
    icon: "StickyNote",
    labelKey: "notesBlock",
    allowMultiple: true,
    createDefault: () => ({ body: "" }),
  },
};

// ─── Shared sub-types ────────────────────────────────────────────────────────

export interface Deliverable {
  id: string;
  number: number;
  title: string;
  description: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export type Currency = "USD" | "EUR" | "MXN" | "COP";
export type QuoteStatus = "draft" | "sent" | "accepted" | "rejected";
export type QuoteLocale = "en" | "es";

// ─── Quote ───────────────────────────────────────────────────────────────────

export interface Quote {
  id: string;
  clientName: string;
  clientEmail: string;
  clientCompany: string;
  title: string;
  currency: Currency;
  status: QuoteStatus;
  validUntil: string;
  locale: QuoteLocale;
  blocks: QuoteBlock[];
  createdAt: string;
  updatedAt: string;
}

// ─── Currency helpers ────────────────────────────────────────────────────────

export const CURRENCY_SYMBOLS: Record<Currency, string> = {
  USD: "$",
  EUR: "\u20AC",
  MXN: "$",
  COP: "$",
};

export const CURRENCY_LABELS: Record<Currency, string> = {
  USD: "USD ($)",
  EUR: "EUR (\u20AC)",
  MXN: "MXN ($)",
  COP: "COP ($)",
};

export function formatCurrency(
  amount: number,
  currency: Currency,
  locale: string = "en"
): string {
  return new Intl.NumberFormat(locale === "es" ? "es-MX" : "en-US", {
    style: "currency",
    currency,
    minimumFractionDigits: 2,
  }).format(amount);
}

// ─── Calculation helpers ─────────────────────────────────────────────────────

export function calculateLineItemTotal(item: LineItem): number {
  return item.quantity * item.unitPrice;
}

export function calculateSubtotal(items: LineItem[]): number {
  return items.reduce((sum, item) => sum + calculateLineItemTotal(item), 0);
}

export function calculateTotal(items: LineItem[], discount: number): number {
  const subtotal = calculateSubtotal(items);
  return subtotal - subtotal * (discount / 100);
}

/** Sum all line-items totals + pricing fixedPrice across blocks */
export function getQuoteDisplayTotal(
  blocks: QuoteBlock[],
  currency: Currency,
  locale: string
): string {
  let total = 0;

  for (const block of blocks) {
    if (block.type === "line-items") {
      total += calculateTotal(block.data.items, block.data.discount);
    } else if (block.type === "pricing") {
      total += block.data.fixedPrice;
    }
  }

  return formatCurrency(total, currency, locale);
}

import { z } from "zod";

// ─── Sub-schemas ─────────────────────────────────────────────────────────────

export const lineItemSchema = z.object({
  id: z.string(),
  description: z.string().min(1, "Description is required"),
  quantity: z.number().min(1, "Quantity must be at least 1"),
  unitPrice: z.number().min(0, "Price must be positive"),
});

export const deliverableSchema = z.object({
  id: z.string(),
  number: z.number().min(1),
  title: z.string().min(1, "Deliverable title is required"),
  description: z.string().min(1, "Deliverable description is required"),
});

// ─── Block schemas ───────────────────────────────────────────────────────────

const textBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("text"),
  order: z.number(),
  data: z.object({
    heading: z.string(),
    body: z.string(),
  }),
});

const lineItemsBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("line-items"),
  order: z.number(),
  data: z.object({
    heading: z.string(),
    items: z.array(lineItemSchema),
    discount: z.number().min(0).max(100).default(0),
  }),
});

const deliverablesBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("deliverables"),
  order: z.number(),
  data: z.object({
    items: z.array(deliverableSchema),
  }),
});

const pricingBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("pricing"),
  order: z.number(),
  data: z.object({
    fixedPrice: z.number().min(0),
    listPrice: z.number().optional(),
    preferentialNote: z.string().optional(),
    timeline: z.string().optional(),
    paymentTerms: z.string().optional(),
  }),
});

const nextStepsBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("next-steps"),
  order: z.number(),
  data: z.object({
    steps: z.array(z.string()),
  }),
});

const notesBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("notes"),
  order: z.number(),
  data: z.object({
    body: z.string(),
  }),
});

export const quoteBlockSchema = z.discriminatedUnion("type", [
  textBlockSchema,
  lineItemsBlockSchema,
  deliverablesBlockSchema,
  pricingBlockSchema,
  nextStepsBlockSchema,
  notesBlockSchema,
]);

// ─── Quote form schema ───────────────────────────────────────────────────────

export const quoteFormSchema = z.object({
  clientName: z.string().min(1, "Client name is required"),
  clientEmail: z.string().email("Valid email is required"),
  clientCompany: z.string().default(""),
  title: z.string().min(1, "Quote title is required"),
  currency: z.enum(["USD", "EUR", "MXN", "COP"]),
  validUntil: z.string().default(""),
  locale: z.enum(["en", "es"]).default("en"),
  status: z.enum(["draft", "sent", "accepted", "rejected"]).default("draft"),
  blocks: z.array(quoteBlockSchema).min(1, "At least one block is required"),
});

export type QuoteFormData = z.infer<typeof quoteFormSchema>;

