"use client";

import { useTranslations } from "next-intl";
import { Card } from "@/shared/components/ui/Card";
import { ChevronUp, ChevronDown, X, Type, Table, ListChecks, DollarSign, ListOrdered, StickyNote } from "lucide-react";
import { BLOCK_REGISTRY, type QuoteBlock } from "../../types";
import { TextBlockEditor } from "./TextBlockEditor";
import { LineItemsBlockEditor } from "./LineItemsBlockEditor";
import { DeliverablesBlockEditor } from "./DeliverablesBlockEditor";
import { PricingBlockEditor } from "./PricingBlockEditor";
import { NextStepsBlockEditor } from "./NextStepsBlockEditor";
import { NotesBlockEditor } from "./NotesBlockEditor";
import type { Currency } from "../../types";

const ICON_MAP = {
  Type,
  Table,
  ListChecks,
  DollarSign,
  ListOrdered,
  StickyNote,
} as const;

interface BlockEditorProps {
  block: QuoteBlock;
  currency: Currency;
  locale: string;
  isFirst: boolean;
  isLast: boolean;
  onUpdate: (block: QuoteBlock) => void;
  onMoveUp: () => void;
  onMoveDown: () => void;
  onRemove: () => void;
}

export function BlockEditor({
  block,
  currency,
  locale,
  isFirst,
  isLast,
  onUpdate,
  onMoveUp,
  onMoveDown,
  onRemove,
}: BlockEditorProps) {
  const t = useTranslations("Admin");
  const config = BLOCK_REGISTRY[block.type];
  const Icon = ICON_MAP[config.icon as keyof typeof ICON_MAP];

  function renderEditor() {
    switch (block.type) {
      case "text":
        return <TextBlockEditor block={block} onUpdate={onUpdate} />;
      case "line-items":
        return <LineItemsBlockEditor block={block} currency={currency} locale={locale} onUpdate={onUpdate} />;
      case "deliverables":
        return <DeliverablesBlockEditor block={block} onUpdate={onUpdate} />;
      case "pricing":
        return <PricingBlockEditor block={block} onUpdate={onUpdate} />;
      case "next-steps":
        return <NextStepsBlockEditor block={block} onUpdate={onUpdate} />;
      case "notes":
        return <NotesBlockEditor block={block} onUpdate={onUpdate} />;
    }
  }

  return (
    <Card>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Icon size={16} className="text-pragma-accent" />
          <h3 className="text-sm font-semibold text-pragma-muted uppercase tracking-wider">
            {t(config.labelKey)}
          </h3>
        </div>
        <div className="flex items-center gap-1">
          <button
            type="button"
            onClick={onMoveUp}
            disabled={isFirst}
            className="p-1 text-pragma-muted hover:text-pragma-text disabled:opacity-30 transition-colors cursor-pointer disabled:cursor-not-allowed"
            title={t("moveUp")}
          >
            <ChevronUp size={16} />
          </button>
          <button
            type="button"
            onClick={onMoveDown}
            disabled={isLast}
            className="p-1 text-pragma-muted hover:text-pragma-text disabled:opacity-30 transition-colors cursor-pointer disabled:cursor-not-allowed"
            title={t("moveDown")}
          >
            <ChevronDown size={16} />
          </button>
          <button
            type="button"
            onClick={onRemove}
            className="p-1 text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
            title={t("removeBlock")}
          >
            <X size={16} />
          </button>
        </div>
      </div>
      {renderEditor()}
    </Card>
  );
}

