import type { QuoteBlock, Currency } from "../../types";
import { TextBlockViewer } from "./TextBlockViewer";
import { LineItemsBlockViewer } from "./LineItemsBlockViewer";
import { DeliverablesBlockViewer } from "./DeliverablesBlockViewer";
import { PricingBlockViewer } from "./PricingBlockViewer";
import { NextStepsBlockViewer } from "./NextStepsBlockViewer";
import { NotesBlockViewer } from "./NotesBlockViewer";

interface BlockViewerProps {
  block: QuoteBlock;
  currency: Currency;
  locale: string;
}

export function BlockViewer({ block, currency, locale }: BlockViewerProps) {
  switch (block.type) {
    case "text":
      return <TextBlockViewer block={block} />;
    case "line-items":
      return <LineItemsBlockViewer block={block} currency={currency} locale={locale} />;
    case "deliverables":
      return <DeliverablesBlockViewer block={block} />;
    case "pricing":
      return <PricingBlockViewer block={block} currency={currency} locale={locale} />;
    case "next-steps":
      return <NextStepsBlockViewer block={block} />;
    case "notes":
      return <NotesBlockViewer block={block} />;
  }
}

