"use client";

import { useState, useRef, useEffect } from "react";
import { useTranslations } from "next-intl";
import { Plus, Type, Table, ListChecks, DollarSign, ListOrdered, StickyNote } from "lucide-react";
import { Button } from "@/shared/components/ui/Button";
import { BLOCK_REGISTRY, type BlockType, type QuoteBlock } from "../../types";

const ICON_MAP = {
  Type,
  Table,
  ListChecks,
  DollarSign,
  ListOrdered,
  StickyNote,
} as const;

interface AddBlockMenuProps {
  existingBlocks: QuoteBlock[];
  onAdd: (type: BlockType) => void;
}

export function AddBlockMenu({ existingBlocks, onAdd }: AddBlockMenuProps) {
  const t = useTranslations("Admin");
  const [open, setOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    if (open) document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [open]);

  const blockTypes = Object.entries(BLOCK_REGISTRY) as [BlockType, (typeof BLOCK_REGISTRY)[BlockType]][];

  return (
    <div className="relative" ref={menuRef}>
      <Button
        type="button"
        variant="secondary"
        size="md"
        onClick={() => setOpen(!open)}
        className="w-full border-dashed"
      >
        <Plus size={16} />
        {t("addBlock")}
      </Button>

      {open && (
        <div className="absolute z-20 mt-2 w-full bg-pragma-surface border border-pragma-border rounded-xl shadow-lg overflow-hidden">
          {blockTypes.map(([type, config]) => {
            const Icon = ICON_MAP[config.icon as keyof typeof ICON_MAP];
            const alreadyExists = existingBlocks.some((b) => b.type === type);
            const disabled = !config.allowMultiple && alreadyExists;

            return (
              <button
                key={type}
                type="button"
                disabled={disabled}
                onClick={() => {
                  onAdd(type);
                  setOpen(false);
                }}
                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-left hover:bg-pragma-accent/10 transition-colors disabled:opacity-40 disabled:cursor-not-allowed cursor-pointer"
              >
                <Icon size={16} className="text-pragma-accent shrink-0" />
                <span>{t(config.labelKey)}</span>
                {disabled && (
                  <span className="ml-auto text-xs text-pragma-muted">(max 1)</span>
                )}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

import {
  Document,
  Page,
  Text,
  View,
  StyleSheet,
} from "@react-pdf/renderer";
import type { Quote, QuoteBlock, TextBlock, LineItemsBlock, DeliverablesBlock, PricingBlock, NextStepsBlock, NotesBlock } from "../types";
import {
  formatCurrency,
  calculateLineItemTotal,
  calculateSubtotal,
  calculateTotal,
} from "../types";

const colors = {
  accent: "#00f0ff",
  muted: "#71717a",
};

const styles = StyleSheet.create({
  page: {
    padding: 40,
    backgroundColor: "#ffffff",
    color: "#1a1a2e",
    fontFamily: "Helvetica",
    fontSize: 10,
  },
  header: {
    flexDirection: "row",
    justifyContent: "space-between",
    marginBottom: 30,
    paddingBottom: 15,
    borderBottomWidth: 2,
    borderBottomColor: colors.accent,
  },
  logo: {
    fontSize: 24,
    fontFamily: "Helvetica-Bold",
    color: colors.accent,
  },
  headerRight: { textAlign: "right" },
  headerLabel: { fontSize: 8, color: colors.muted, marginBottom: 2 },
  headerValue: { fontSize: 10, marginBottom: 4 },
  title: {
    fontSize: 18,
    fontFamily: "Helvetica-Bold",
    marginBottom: 20,
    color: "#1a1a2e",
  },
  clientBox: {
    backgroundColor: "#f5f5f5",
    borderRadius: 4,
    padding: 12,
    marginBottom: 20,
  },
  clientLabel: {
    fontSize: 8,
    color: colors.muted,
    marginBottom: 6,
    textTransform: "uppercase",
    letterSpacing: 1,
  },
  clientName: { fontSize: 12, fontFamily: "Helvetica-Bold", marginBottom: 2 },
  clientDetail: { fontSize: 9, color: colors.muted },
  // Text block
  narrativeBox: {
    borderLeftWidth: 2,
    borderLeftColor: colors.accent,
    marginBottom: 16,
    backgroundColor: "#f9f9f9",
    padding: 12,
    paddingLeft: 14,
  },
  sectionLabelAccent: {
    fontSize: 8,
    color: colors.accent,
    textTransform: "uppercase",
    letterSpacing: 1,
    marginBottom: 6,
  },
  sectionLabel: {
    fontSize: 8,
    color: colors.muted,
    textTransform: "uppercase",
    letterSpacing: 1,
    marginBottom: 6,
  },
  narrativeText: { fontSize: 10, color: "#333", lineHeight: 1.6 },
  // Line items
  groupHeading: {
    fontSize: 8,
    color: colors.muted,
    textTransform: "uppercase",
    letterSpacing: 1,
    marginBottom: 8,
  },
  tableHeader: {
    flexDirection: "row",
    borderBottomWidth: 1,
    borderBottomColor: "#e0e0e0",
    paddingBottom: 6,
    marginBottom: 4,
  },
  tableHeaderText: {
    fontSize: 8,
    color: colors.muted,
    textTransform: "uppercase",
    letterSpacing: 0.5,
  },
  tableRow: {
    flexDirection: "row",
    paddingVertical: 6,
    borderBottomWidth: 0.5,
    borderBottomColor: "#f0f0f0",
  },
  colDesc: { flex: 5 },
  colQty: { flex: 1, textAlign: "right" },
  colPrice: { flex: 2, textAlign: "right" },
  colTotal: { flex: 2, textAlign: "right" },
  totalsSection: { marginTop: 12, paddingTop: 8, alignItems: "flex-end" },
  totalRow: { flexDirection: "row", justifyContent: "flex-end", marginBottom: 4 },
  totalLabel: { width: 100, textAlign: "right", color: colors.muted, fontSize: 10 },
  totalValue: { width: 100, textAlign: "right", fontSize: 10 },
  grandTotal: {
    flexDirection: "row",
    justifyContent: "flex-end",
    borderTopWidth: 2,
    borderTopColor: colors.accent,
    paddingTop: 6,
    marginTop: 4,
  },
  grandTotalLabel: { width: 100, textAlign: "right", fontSize: 14, fontFamily: "Helvetica-Bold" },
  grandTotalValue: { width: 100, textAlign: "right", fontSize: 14, fontFamily: "Helvetica-Bold", color: "#0066cc" },
  // Deliverables
  deliverableRow: {
    flexDirection: "row",
    marginBottom: 10,
    backgroundColor: "#f9f9f9",
    padding: 10,
    borderRadius: 4,
  },
  deliverableNumber: {
    fontSize: 14,
    fontFamily: "Helvetica-Bold",
    color: colors.accent,
    width: 24,
    marginRight: 8,
  },
  deliverableContent: { flex: 1 },
  deliverableTitle: { fontSize: 10, fontFamily: "Helvetica-Bold", marginBottom: 3 },
  deliverableDesc: { fontSize: 9, color: colors.muted, lineHeight: 1.4 },
  // Pricing
  timelineInvestmentRow: { flexDirection: "row", gap: 12, marginBottom: 16 },
  timelineBox: { flex: 1, backgroundColor: "#f5f5f5", borderRadius: 4, padding: 12 },
  investmentBox: {
    flex: 1,
    backgroundColor: "#f5f5f5",
    borderRadius: 4,
    padding: 12,
    borderWidth: 1,
    borderColor: "#b3f7ff",
  },
  timelineValue: { fontSize: 16, fontFamily: "Helvetica-Bold", marginTop: 4 },
  listPriceText: { fontSize: 10, color: colors.muted, textDecoration: "line-through" },
  preferentialText: { fontSize: 8, color: colors.muted, fontStyle: "italic", marginBottom: 2 },
  fixedPriceText: { fontSize: 16, fontFamily: "Helvetica-Bold", color: "#0066cc", marginTop: 2 },
  paymentTermsText: { fontSize: 8, color: colors.muted, marginTop: 4 },
  // Next steps
  nextStepRow: { flexDirection: "row", marginBottom: 6 },
  nextStepNum: { fontSize: 10, color: colors.accent, width: 20, fontFamily: "Helvetica-Bold" },
  nextStepText: { flex: 1, fontSize: 10, color: "#333" },
  // Notes
  notesBox: { marginTop: 8, backgroundColor: "#fafafa", borderRadius: 4, padding: 12 },
  notesText: { fontSize: 9, color: "#555", lineHeight: 1.5, fontStyle: "italic" },
  divider: { borderBottomWidth: 1, borderBottomColor: "#e0e0e0", marginVertical: 16 },
  // Footer
  footer: {
    position: "absolute",
    bottom: 30,
    left: 40,
    right: 40,
    borderTopWidth: 1,
    borderTopColor: "#b3f7ff",
    paddingTop: 10,
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
  },
  footerText: { fontSize: 8, color: colors.muted },
  footerBrand: { fontSize: 9, fontFamily: "Helvetica-Bold", color: "#1a1a2e", marginBottom: 1 },
  footerConfidential: { fontSize: 7, color: colors.muted, textTransform: "uppercase", letterSpacing: 0.5 },
});

function LogoMark() {
  return (
    <View style={{ flexDirection: "row", alignItems: "center" }}>
      <View
        style={{
          width: 28,
          height: 28,
          backgroundColor: colors.accent,
          borderRadius: 3,
          alignItems: "center",
          justifyContent: "center",
          marginRight: 10,
        }}
      >
        <Text style={{ fontSize: 15, fontFamily: "Helvetica-Bold", color: "#0a0a0f" }}>
          P
        </Text>
      </View>
      <Text style={styles.logo}>PRAGMA</Text>
    </View>
  );
}

// ─── Per-block PDF renderers ─────────────────────────────────────────────────

function TextBlockPdf({ block }: { block: TextBlock }) {
  if (!block.data.heading && !block.data.body) return null;
  return (
    <View style={styles.narrativeBox}>
      {block.data.heading && (
        <Text style={styles.sectionLabelAccent}>{block.data.heading}</Text>
      )}
      {block.data.body && (
        <Text style={styles.narrativeText}>{block.data.body}</Text>
      )}
    </View>
  );
}

function LineItemsBlockPdf({
  block,
  currency,
  locale,
}: {
  block: LineItemsBlock;
  currency: Quote["currency"];
  locale: string;
}) {
  const { items, discount, heading } = block.data;
  if (items.length === 0) return null;

  const subtotal = calculateSubtotal(items);
  const discountAmount = subtotal * (discount / 100);
  const total = calculateTotal(items, discount);

  return (
    <View style={{ marginBottom: 16 }}>
      {heading && <Text style={styles.groupHeading}>{heading}</Text>}

      <View style={styles.tableHeader}>
        <Text style={[styles.tableHeaderText, styles.colDesc]}>Description</Text>
        <Text style={[styles.tableHeaderText, styles.colQty]}>Qty</Text>
        <Text style={[styles.tableHeaderText, styles.colPrice]}>Unit Price</Text>
        <Text style={[styles.tableHeaderText, styles.colTotal]}>Total</Text>
      </View>

      {items.map((item) => (
        <View key={item.id} style={styles.tableRow}>
          <Text style={styles.colDesc}>{item.description}</Text>
          <Text style={styles.colQty}>{item.quantity}</Text>
          <Text style={styles.colPrice}>
            {formatCurrency(item.unitPrice, currency, locale)}
          </Text>
          <Text style={styles.colTotal}>
            {formatCurrency(calculateLineItemTotal(item), currency, locale)}
          </Text>
        </View>
      ))}

      <View style={styles.totalsSection}>
        <View style={styles.totalRow}>
          <Text style={styles.totalLabel}>Subtotal:</Text>
          <Text style={styles.totalValue}>
            {formatCurrency(subtotal, currency, locale)}
          </Text>
        </View>
        {discount > 0 && (
          <View style={styles.totalRow}>
            <Text style={styles.totalLabel}>Discount ({discount}%):</Text>
            <Text style={[styles.totalValue, { color: "#cc0000" }]}>
              -{formatCurrency(discountAmount, currency, locale)}
            </Text>
          </View>
        )}
        <View style={styles.grandTotal}>
          <Text style={styles.grandTotalLabel}>Total:</Text>
          <Text style={styles.grandTotalValue}>
            {formatCurrency(total, currency, locale)}
          </Text>
        </View>
      </View>
    </View>
  );
}

function DeliverablesBlockPdf({ block }: { block: DeliverablesBlock }) {
  const { items } = block.data;
  if (items.length === 0) return null;

  return (
    <View style={{ marginBottom: 16 }}>
      <Text style={styles.sectionLabel}>Deliverables</Text>
      {items.map((d) => (
        <View key={d.id} style={styles.deliverableRow}>
          <Text style={styles.deliverableNumber}>{d.number}</Text>
          <View style={styles.deliverableContent}>
            <Text style={styles.deliverableTitle}>{d.title}</Text>
            <Text style={styles.deliverableDesc}>{d.description}</Text>
          </View>
        </View>
      ))}
    </View>
  );
}

function PricingBlockPdf({
  block,
  currency,
  locale,
}: {
  block: PricingBlock;
  currency: Quote["currency"];
  locale: string;
}) {
  const { fixedPrice, listPrice, preferentialNote, timeline, paymentTerms } = block.data;

  return (
    <View style={styles.timelineInvestmentRow}>
      {timeline && (
        <View style={styles.timelineBox}>
          <Text style={styles.sectionLabel}>Timeline</Text>
          <Text style={styles.timelineValue}>{timeline}</Text>
        </View>
      )}

      <View style={styles.investmentBox}>
        <Text style={styles.sectionLabel}>Investment</Text>
        {listPrice != null && (
          <Text style={styles.listPriceText}>
            {formatCurrency(listPrice, currency, locale)}
          </Text>
        )}
        {preferentialNote && (
          <Text style={styles.preferentialText}>{preferentialNote}</Text>
        )}
        <Text style={styles.fixedPriceText}>
          {formatCurrency(fixedPrice, currency, locale)}
        </Text>
        {paymentTerms && (
          <Text style={styles.paymentTermsText}>{paymentTerms}</Text>
        )}
      </View>
    </View>
  );
}

function NextStepsBlockPdf({ block }: { block: NextStepsBlock }) {
  const { steps } = block.data;
  if (steps.length === 0) return null;

  return (
    <View style={{ marginBottom: 16 }}>
      <Text style={styles.sectionLabel}>Next Steps</Text>
      {steps.map((step, i) => (
        <View key={i} style={styles.nextStepRow}>
          <Text style={styles.nextStepNum}>{i + 1}.</Text>
          <Text style={styles.nextStepText}>{step}</Text>
        </View>
      ))}
    </View>
  );
}

function NotesBlockPdf({ block }: { block: NotesBlock }) {
  if (!block.data.body) return null;
  return (
    <View style={styles.notesBox}>
      <Text style={styles.notesText}>{block.data.body}</Text>
    </View>
  );
}

function renderBlock(block: QuoteBlock, currency: Quote["currency"], locale: string) {
  switch (block.type) {
    case "text":
      return <TextBlockPdf key={block.blockId} block={block} />;
    case "line-items":
      return <LineItemsBlockPdf key={block.blockId} block={block} currency={currency} locale={locale} />;
    case "deliverables":
      return <DeliverablesBlockPdf key={block.blockId} block={block} />;
    case "pricing":
      return <PricingBlockPdf key={block.blockId} block={block} currency={currency} locale={locale} />;
    case "next-steps":
      return <NextStepsBlockPdf key={block.blockId} block={block} />;
    case "notes":
      return <NotesBlockPdf key={block.blockId} block={block} />;
  }
}

// ─── Main export ─────────────────────────────────────────────────────────────

export function QuotePdfDocument({ quote }: { quote: Quote }) {
  const isEs = quote.locale === "es";

  return (
    <Document>
      <Page size="A4" style={styles.page}>
        {/* Header */}
        <View style={styles.header}>
          <LogoMark />
          <View style={styles.headerRight}>
            <Text style={styles.headerLabel}>{isEs ? "PROPUESTA" : "QUOTE"}</Text>
            <Text style={styles.headerValue}>#{quote.id}</Text>
            <Text style={styles.headerLabel}>{isEs ? "FECHA" : "DATE"}</Text>
            <Text style={styles.headerValue}>
              {new Date(quote.createdAt).toLocaleDateString(isEs ? "es-MX" : "en-US")}
            </Text>
            {quote.validUntil && (
              <>
                <Text style={styles.headerLabel}>
                  {isEs ? "VALIDO HASTA" : "VALID UNTIL"}
                </Text>
                <Text style={styles.headerValue}>{quote.validUntil}</Text>
              </>
            )}
          </View>
        </View>

        {/* Title */}
        <Text style={styles.title}>{quote.title}</Text>

        {/* Client */}
        <View style={styles.clientBox}>
