"use client";

import { useTranslations } from "next-intl";
import { Button } from "@/shared/components/ui/Button";
import { Plus, X } from "lucide-react";
import type { NextStepsBlock, QuoteBlock } from "../../types";

interface Props {
  block: NextStepsBlock;
  onUpdate: (block: QuoteBlock) => void;
}

export function NextStepsBlockEditor({ block, onUpdate }: Props) {
  const t = useTranslations("Admin");
  const { steps } = block.data;

  function updateSteps(newSteps: string[]) {
    onUpdate({ ...block, data: { steps: newSteps } });
  }

  return (
    <div className="space-y-2">
      {steps.map((step, i) => (
        <div key={i} className="flex items-center gap-3">
          <span className="text-pragma-muted text-sm w-5 shrink-0">{i + 1}.</span>
          <input
            type="text"
            value={step}
            onChange={(e) =>
              updateSteps(steps.map((s, idx) => (idx === i ? e.target.value : s)))
            }
            placeholder={`${t("nextStep")} ${i + 1}...`}
            className="flex-1 bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
          />
          <button
            type="button"
            onClick={() => updateSteps(steps.filter((_, idx) => idx !== i))}
            className="text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
          >
            <X size={16} />
          </button>
        </div>
      ))}
      <Button
        type="button"
        variant="ghost"
        size="sm"
        onClick={() => updateSteps([...steps, ""])}
      >
        <Plus size={14} />
        {t("addNextStep")}
      </Button>
    </div>
  );
}

