// ─── Block system ────────────────────────────────────────────────────────────

export type BlockType = "text" | "line-items" | "deliverables" | "pricing" | "next-steps" | "notes";

export interface BaseBlock {
  blockId: string;
  type: BlockType;
  order: number;
}

export interface TextBlock extends BaseBlock {
  type: "text";
  data: { heading: string; body: string };
}

export interface LineItemsBlock extends BaseBlock {
  type: "line-items";
  data: { heading: string; items: LineItem[]; discount: number };
}

export interface DeliverablesBlock extends BaseBlock {
  type: "deliverables";
  data: { items: Deliverable[] };
}

export interface PricingBlock extends BaseBlock {
  type: "pricing";
  data: {
    fixedPrice: number;
    listPrice?: number;
    preferentialNote?: string;
    timeline?: string;
    paymentTerms?: string;
  };
}

export interface NextStepsBlock extends BaseBlock {
  type: "next-steps";
  data: { steps: string[] };
}

export interface NotesBlock extends BaseBlock {
  type: "notes";
  data: { body: string };
}

export type QuoteBlock =
  | TextBlock
  | LineItemsBlock
  | DeliverablesBlock
  | PricingBlock
  | NextStepsBlock
  | NotesBlock;

// ─── Block registry ──────────────────────────────────────────────────────────

export const BLOCK_REGISTRY: Record<
  BlockType,
  {
    icon: string;
    labelKey: string;
    allowMultiple: boolean;
    createDefault: () => QuoteBlock["data"];
  }
> = {
  text: {
    icon: "Type",
    labelKey: "textSection",
    allowMultiple: true,
    createDefault: () => ({ heading: "", body: "" }),
  },
  "line-items": {
    icon: "Table",
    labelKey: "lineItemsBlock",
    allowMultiple: true,
    createDefault: () => ({
      heading: "",
      items: [{ id: crypto.randomUUID().slice(0, 6), description: "", quantity: 1, unitPrice: 0 }],
      discount: 0,
    }),
  },
  deliverables: {
    icon: "ListChecks",
    labelKey: "deliverablesBlock",
    allowMultiple: true,
    createDefault: () => ({ items: [] }),
  },
  pricing: {
    icon: "DollarSign",
    labelKey: "pricingBlock",
    allowMultiple: false,
    createDefault: () => ({ fixedPrice: 0 }),
  },
  "next-steps": {
    icon: "ListOrdered",
    labelKey: "nextStepsBlock",
    allowMultiple: false,
    createDefault: () => ({ steps: [""] }),
  },
  notes: {
    icon: "StickyNote",
    labelKey: "notesBlock",
    allowMultiple: true,
    createDefault: () => ({ body: "" }),
  },
};

// ─── Shared sub-types ────────────────────────────────────────────────────────

export interface Deliverable {
  id: string;
  number: number;
  title: string;
  description: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export type Currency = "USD" | "EUR" | "MXN" | "COP";
export type QuoteStatus = "draft" | "sent" | "accepted" | "rejected";
export type QuoteLocale = "en" | "es";

// ─── Quote ───────────────────────────────────────────────────────────────────

export interface Quote {
  id: string;
  clientName: string;
  clientEmail: string;
  clientCompany: string;
  title: string;
  currency: Currency;
  status: QuoteStatus;
  validUntil: string;
  locale: QuoteLocale;
  blocks: QuoteBlock[];
  createdAt: string;
  updatedAt: string;
}

// ─── Currency helpers ────────────────────────────────────────────────────────

export const CURRENCY_SYMBOLS: Record<Currency, string> = {
  USD: "$",
  EUR: "\u20AC",
  MXN: "$",
  COP: "$",
};

export const CURRENCY_LABELS: Record<Currency, string> = {
  USD: "USD ($)",
  EUR: "EUR (\u20AC)",
  MXN: "MXN ($)",
  COP: "COP ($)",
};

export function formatCurrency(
  amount: number,
  currency: Currency,
  locale: string = "en"
): string {
  return new Intl.NumberFormat(locale === "es" ? "es-MX" : "en-US", {
    style: "currency",
    currency,
    minimumFractionDigits: 2,
  }).format(amount);
}

// ─── Calculation helpers ─────────────────────────────────────────────────────

export function calculateLineItemTotal(item: LineItem): number {
  return item.quantity * item.unitPrice;
}

export function calculateSubtotal(items: LineItem[]): number {
  return items.reduce((sum, item) => sum + calculateLineItemTotal(item), 0);
}

export function calculateTotal(items: LineItem[], discount: number): number {
  const subtotal = calculateSubtotal(items);
  return subtotal - subtotal * (discount / 100);
}

/** Sum all line-items totals + pricing fixedPrice across blocks */
export function getQuoteDisplayTotal(
  blocks: QuoteBlock[],
  currency: Currency,
  locale: string
): string {
  let total = 0;

  for (const block of blocks) {
    if (block.type === "line-items") {
      total += calculateTotal(block.data.items, block.data.discount);
    } else if (block.type === "pricing") {
      total += block.data.fixedPrice;
    }
  }

  return formatCurrency(total, currency, locale);
}

