// ─── Block system ────────────────────────────────────────────────────────────

export type BlockType = "text" | "line-items" | "deliverables" | "pricing" | "next-steps" | "notes" | "phase" | "table" | "divider";

export interface BaseBlock {
  blockId: string;
  type: BlockType;
  order: number;
}

export interface TextBlock extends BaseBlock {
  type: "text";
  data: { heading: string; body: string };
}

export interface LineItemsBlock extends BaseBlock {
  type: "line-items";
  data: { heading: string; items: LineItem[]; discount: number };
}

export interface DeliverablesBlock extends BaseBlock {
  type: "deliverables";
  data: { items: Deliverable[] };
}

export interface PricingBlock extends BaseBlock {
  type: "pricing";
  data: {
    fixedPrice: number;
    listPrice?: number;
    preferentialNote?: string;
    timeline?: string;
    paymentTerms?: string;
  };
}

export interface NextStepsBlock extends BaseBlock {
  type: "next-steps";
  data: { steps: string[] };
}

export interface NotesBlock extends BaseBlock {
  type: "notes";
  data: { body: string };
}

export interface PhaseBlock extends BaseBlock {
  type: "phase";
  data: {
    phaseNumber: number;
    title: string;
    description: string;
    scope: { title: string; description: string }[];
    result: string;
    duration: string;
  };
}

export interface TableBlock extends BaseBlock {
  type: "table";
  data: {
    heading: string;
    columns: string[];
    rows: string[][];
    highlightLastRow: boolean;
  };
}

export interface DividerBlock extends BaseBlock {
  type: "divider";
  data: Record<string, never>;
}

export type QuoteBlock =
  | TextBlock
  | LineItemsBlock
  | DeliverablesBlock
  | PricingBlock
  | NextStepsBlock
  | NotesBlock
  | PhaseBlock
  | TableBlock
  | DividerBlock;

