import { z } from "zod";

// ─── Sub-schemas ─────────────────────────────────────────────────────────────

export const lineItemSchema = z.object({
  id: z.string(),
  description: z.string().min(1, "Description is required"),
  quantity: z.number().min(1, "Quantity must be at least 1"),
  unitPrice: z.number().min(0, "Price must be positive"),
});

export const deliverableSchema = z.object({
  id: z.string(),
  number: z.number().min(1),
  title: z.string().min(1, "Deliverable title is required"),
  description: z.string().min(1, "Deliverable description is required"),
});

// ─── Block schemas ───────────────────────────────────────────────────────────

const textBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("text"),
  order: z.number(),
  data: z.object({
    heading: z.string(),
    body: z.string(),
  }),
});

const lineItemsBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("line-items"),
  order: z.number(),
  data: z.object({
    heading: z.string(),
    items: z.array(lineItemSchema),
    discount: z.number().min(0).max(100).default(0),
  }),
});

const deliverablesBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("deliverables"),
  order: z.number(),
  data: z.object({
    items: z.array(deliverableSchema),
  }),
});

const pricingBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("pricing"),
  order: z.number(),
  data: z.object({
    fixedPrice: z.number().min(0),
    listPrice: z.number().optional(),
    preferentialNote: z.string().optional(),
    timeline: z.string().optional(),
    paymentTerms: z.string().optional(),
  }),
});

const nextStepsBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("next-steps"),
  order: z.number(),
  data: z.object({
    steps: z.array(z.string()),
  }),
});

const notesBlockSchema = z.object({
  blockId: z.string(),
  type: z.literal("notes"),
  order: z.number(),
  data: z.object({
    body: z.string(),
  }),
});

export const quoteBlockSchema = z.discriminatedUnion("type", [
  textBlockSchema,
  lineItemsBlockSchema,
  deliverablesBlockSchema,
  pricingBlockSchema,
  nextStepsBlockSchema,
  notesBlockSchema,
]);

// ─── Quote form schema ───────────────────────────────────────────────────────

export const quoteFormSchema = z.object({
  clientName: z.string().min(1, "Client name is required"),
  clientEmail: z.string().email("Valid email is required"),
  clientCompany: z.string().default(""),
  title: z.string().min(1, "Quote title is required"),
  currency: z.enum(["USD", "EUR", "MXN", "COP"]),
  validUntil: z.string().default(""),
  locale: z.enum(["en", "es"]).default("en"),
  status: z.enum(["draft", "sent", "accepted", "rejected"]).default("draft"),
  blocks: z.array(quoteBlockSchema).min(1, "At least one block is required"),
});

export type QuoteFormData = z.infer<typeof quoteFormSchema>;

