"use client";

import { useTranslations } from "next-intl";
import { Input } from "@/shared/components/ui/Input";
import { Textarea } from "@/shared/components/ui/Textarea";
import { Button } from "@/shared/components/ui/Button";
import { Plus, X } from "lucide-react";
import type { PhaseBlock, QuoteBlock } from "../../types";

interface Props {
  block: PhaseBlock;
  onUpdate: (block: QuoteBlock) => void;
}

export function PhaseBlockEditor({ block, onUpdate }: Props) {
  const t = useTranslations("Admin");
  const { data } = block;

  function update(patch: Partial<PhaseBlock["data"]>) {
    onUpdate({ ...block, data: { ...data, ...patch } });
  }

  function updateScope(index: number, field: "title" | "description", value: string) {
    const scope = data.scope.map((s, i) =>
      i === index ? { ...s, [field]: value } : s
    );
    update({ scope });
  }

  return (
    <div className="space-y-3">
      <div className="flex gap-3">
        <div className="w-24">
          <Input
            id={`${block.blockId}-phaseNum`}
            label={t("phaseNumber")}
            type="number"
            min={1}
            value={data.phaseNumber}
            onChange={(e) => update({ phaseNumber: parseInt(e.target.value) || 1 })}
          />
        </div>
        <div className="flex-1">
          <Input
            id={`${block.blockId}-title`}
            label={t("phaseTitle")}
            value={data.title}
            onChange={(e) => update({ title: e.target.value })}
            placeholder="e.g. Platform Foundation"
          />
        </div>
      </div>

      <Textarea
        id={`${block.blockId}-desc`}
        label={t("phaseDescription")}
        value={data.description}
        onChange={(e) => update({ description: e.target.value })}
        placeholder="Introductory paragraph for this phase..."
      />

      <div>
        <p className="text-xs font-semibold text-pragma-muted uppercase tracking-wider mb-2">
          {t("scopeItems")}
        </p>
        {data.scope.map((item, i) => (
          <div key={i} className="flex gap-2 mb-2">
            <input
              type="text"
              value={item.title}
              onChange={(e) => updateScope(i, "title", e.target.value)}
              placeholder="Title"
              className="w-1/3 bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
            />
            <input
              type="text"
              value={item.description}
              onChange={(e) => updateScope(i, "description", e.target.value)}
              placeholder="Description"
              className="flex-1 bg-pragma-surface border border-pragma-border rounded-lg px-3 py-2 text-sm text-pragma-text placeholder:text-pragma-muted/50 focus:outline-none focus:border-pragma-accent/50"
            />
            <button
              type="button"
              onClick={() => update({ scope: data.scope.filter((_, idx) => idx !== i) })}
              className="text-pragma-muted hover:text-red-400 transition-colors cursor-pointer"
            >
              <X size={16} />
            </button>
          </div>
        ))}
        <Button
          type="button"
          variant="ghost"
          size="sm"
          onClick={() => update({ scope: [...data.scope, { title: "", description: "" }] })}
        >
          <Plus size={14} />
          {t("addScopeItem")}
        </Button>
      </div>

      <Textarea
        id={`${block.blockId}-result`}
        label={t("expectedResult")}
        value={data.result}
        onChange={(e) => update({ result: e.target.value })}
        placeholder="Expected outcome of this phase..."
      />

      <Input
        id={`${block.blockId}-duration`}
        label={t("estimatedDuration")}
        value={data.duration}
        onChange={(e) => update({ duration: e.target.value })}
        placeholder="e.g. 2-3 months"
      />
    </div>
  );
}

