import { Card } from "@/shared/components/ui/Card";
import type { PhaseBlock } from "../../types";

export function PhaseBlockViewer({ block }: { block: PhaseBlock }) {
  const { phaseNumber, title, description, scope, result, duration } = block.data;

  return (
    <div className="border-l-2 border-pragma-accent pl-4">
      <Card>
        <div className="flex items-baseline gap-3 mb-3">
          <span className="text-2xl font-bold text-pragma-accent">{phaseNumber}</span>
          <p className="text-xs font-semibold text-pragma-accent uppercase tracking-wider">
            {title}
          </p>
        </div>

        {description && (
          <p className="text-sm text-pragma-text leading-relaxed mb-4 whitespace-pre-wrap">
            {description}
          </p>
        )}

        {scope.length > 0 && (
          <ul className="space-y-2 mb-4">
            {scope.map((item, i) => (
              <li key={i} className="text-sm text-pragma-text">
                <span className="font-semibold">{item.title}</span>
                {item.title && item.description ? " — " : ""}
                <span className="text-pragma-muted">{item.description}</span>
              </li>
            ))}
          </ul>
        )}

        {result && (
          <div className="bg-pragma-accent/5 rounded-lg p-3 mb-3">
            <p className="text-xs font-semibold text-pragma-muted uppercase tracking-wider mb-1">
              Expected Result
            </p>
            <p className="text-sm text-pragma-text">{result}</p>
          </div>
        )}

        {duration && (
          <p className="text-xs text-pragma-muted">
            Duration: <span className="font-semibold text-pragma-text">{duration}</span>
          </p>
        )}
      </Card>
    </div>
  );
}

