import { Card } from "@/shared/components/ui/Card";
import type { TableBlock } from "../../types";

export function TableBlockViewer({ block }: { block: TableBlock }) {
  const { heading, columns, rows, highlightLastRow } = block.data;
  if (columns.length === 0) return null;

  return (
    <Card>
      {heading && (
        <p className="text-xs font-semibold text-pragma-accent uppercase tracking-wider mb-3">
          {heading}
        </p>
      )}
      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-pragma-border">
              {columns.map((col, i) => (
                <th
                  key={i}
                  className="text-left text-xs font-semibold text-pragma-muted uppercase tracking-wider pb-2 pr-4"
                >
                  {col}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {rows.map((row, ri) => {
              const isLast = ri === rows.length - 1;
              const highlight = highlightLastRow && isLast;
              return (
                <tr
                  key={ri}
                  className={
                    highlight
                      ? "border-t-2 border-pragma-accent font-semibold"
                      : "border-b border-pragma-border/50"
                  }
                >
                  {row.map((cell, ci) => (
                    <td key={ci} className="py-2 pr-4 text-pragma-text">
                      {cell}
                    </td>
                  ))}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </Card>
  );
}

