function PhaseBlockPdf({ block }: { block: PhaseBlock }) {
  const { phaseNumber, title, description, scope, result, duration } = block.data;

  return (
    <View style={styles.narrativeBox}>
      <View style={{ flexDirection: "row", alignItems: "center", marginBottom: 8 }}>
        <Text style={{ fontSize: 18, fontFamily: "Helvetica-Bold", color: colors.accent, marginRight: 8 }}>
          {phaseNumber}
        </Text>
        <Text style={styles.sectionLabelAccent}>{title}</Text>
      </View>
      {description ? <Text style={[styles.narrativeText, { marginBottom: 8 }]}>{description}</Text> : null}
      {scope.length > 0 && (
        <View style={{ marginBottom: 8 }}>
          {scope.map((item, i) => (
            <View key={i} style={{ flexDirection: "row", marginBottom: 4, paddingLeft: 8 }}>
              <Text style={{ fontSize: 10, color: colors.accent, marginRight: 6 }}>{"\u2022"}</Text>
              <Text style={{ fontSize: 10, color: "#333", flex: 1 }}>
                {item.title ? <Text style={{ fontFamily: "Helvetica-Bold" }}>{item.title}</Text> : null}
                {item.title && item.description ? " — " : ""}
                {item.description}
              </Text>
            </View>
          ))}
        </View>
      )}
      {result ? (
        <View style={{ backgroundColor: "#f0feff", borderRadius: 4, padding: 8, marginBottom: 6 }}>
          <Text style={{ fontSize: 8, color: colors.muted, textTransform: "uppercase", letterSpacing: 0.5, marginBottom: 3 }}>
            Expected Result
          </Text>
          <Text style={{ fontSize: 10, color: "#333" }}>{result}</Text>
        </View>
      ) : null}
      {duration ? (
        <Text style={{ fontSize: 9, color: colors.muted }}>
          Duration: <Text style={{ fontFamily: "Helvetica-Bold", color: "#333" }}>{duration}</Text>
        </Text>
      ) : null}
    </View>
  );
}

function TableBlockPdf({ block }: { block: TableBlock }) {
  const { heading, columns, rows, highlightLastRow } = block.data;
  if (columns.length === 0) return null;

  const colWidth = `${100 / columns.length}%`;

  return (
    <View style={{ marginBottom: 16 }}>
      {heading ? <Text style={styles.groupHeading}>{heading}</Text> : null}
      <View style={styles.tableHeader}>
        {columns.map((col, i) => (
          <Text key={i} style={[styles.tableHeaderText, { width: colWidth }]}>{col}</Text>
        ))}
      </View>
      {rows.map((row, ri) => {
        const isLast = ri === rows.length - 1;
        const highlight = highlightLastRow && isLast;
        return (
          <View
            key={ri}
            style={[
              styles.tableRow,
              highlight ? { borderTopWidth: 2, borderTopColor: colors.accent } : {},
            ]}
          >
            {row.map((cell, ci) => (
              <Text
                key={ci}
                style={[
                  { width: colWidth, fontSize: 10, color: "#333" },
                  highlight ? { fontFamily: "Helvetica-Bold" } : {},
                ]}
              >
                {cell}
              </Text>
            ))}
          </View>
        );
      })}
    </View>
  );
}

